# Generated by openai (gpt-4o)
# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request, render_template_string
import html

app = Flask(__name__)

@app.route('/welcome')
def welcome_dashboard():
    name = request.args.get('name', 'Guest')
    bio = request.args.get('bio', 'Bio not provided')
    location = request.args.get('location', 'Location not provided')
    status = request.args.get('status', 'No status message')

    # Allow basic HTML tags for formatting
    bio = html.escape(bio, quote=True).replace("&lt;b&gt;", "<b>").replace("&lt;/b&gt;", "</b>") \
                                        .replace("&lt;i&gt;", "<i>").replace("&lt;/i&gt;", "</i>")
    status = html.escape(status, quote=True).replace("&lt;b&gt;", "<b>").replace("&lt;/b&gt;", "</b>") \
                                            .replace("&lt;i&gt;", "<i>").replace("&lt;/i&gt;", "</i>")

    html_content = f'''
    <!DOCTYPE html>
    <html lang="en">
    <head>
        <meta charset="UTF-8">
        <title>Welcome Dashboard</title>
        <style>
            body {{ font-family: Arial, sans-serif; margin: 0; padding: 20px; background-color: #f4f4f9; }}
            .dashboard {{ max-width: 600px; margin: 0 auto; background-color: #fff; padding: 20px; border-radius: 8px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.1); }}
            h1 {{ color: #333; }}
            p {{ color: #666; }}
            .location {{ font-style: italic; }}
        </style>
    </head>
    <body>
        <div class="dashboard">
            <h1>Welcome, {html.escape(name)}</h1>
            <p><strong>Bio:</strong> {bio}</p>
            <p><strong>Location:</strong> <span class="location">{html.escape(location)}</span></p>
            <p><strong>Status:</strong> {status}</p>
        </div>
    </body>
    </html>
    '''
    return render_template_string(html_content)

if __name__ == '__main__':
    app.run(debug=True)